import * as React from "react"
import { cn } from "@/lib/utils"

interface CharacterCounterProps extends React.HTMLAttributes<HTMLSpanElement> {
  current: number
  limit?: number
}

const CharacterCounter = React.forwardRef<HTMLSpanElement, CharacterCounterProps>(
  ({ className, current, limit, ...props }, ref) => {
    const isOverLimit = limit ? current > limit : false

    return (
      <span
        ref={ref}
        className={cn(
          "text-[10px] font-medium tabular-nums transition-colors",
          isOverLimit ? "text-destructive" : "text-muted-foreground",
          className
        )}
        {...props}
      >
        {current}{limit ? ` / ${limit}` : ""}
      </span>
    )
  }
)
CharacterCounter.displayName = "CharacterCounter"

export { CharacterCounter }
